-- Non-idempotent (runs 3x = 3x data):
INSERT INTO summary SELECT date, SUM(amount) FROM sales GROUP BY date;

-- Idempotent (safe to rerun):
DELETE FROM summary WHERE date = '2024-01-15';
INSERT INTO summary SELECT date, SUM(amount) FROM sales WHERE date = '2024-01-15' GROUP BY date;

-- Or using UPSERT:
INSERT INTO summary (date, total)
SELECT date, SUM(amount) FROM sales GROUP BY date
ON CONFLICT (date) DO UPDATE SET total = EXCLUDED.total;

